1	type Item = { type: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
7	const THREE_ALIKE_BLOCK_PREMIUM = 60;
8	
9	type ItemTypeSpec = { basePremium: number; isComponent: boolean };
10	
11	const ITEM_TYPES: Record<string, ItemTypeSpec> = {
12	  // Whole items
13	  sword: { basePremium: 100, isComponent: false },
14	  amulet: { basePremium: 60, isComponent: false },
15	  staff: { basePremium: 80, isComponent: false },
16	  potion: { basePremium: 40, isComponent: false },
17	  // Components (eligible for 3-alike block premium)
18	  rune: { basePremium: 25, isComponent: true },
19	  moonstone: { basePremium: 25, isComponent: true },
20	};
21	
22	const countByType = (items: Item[]): Map<string, number> =>
23	  items.reduce(
24	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
25	    new Map<string, number>(),
26	  );
27	
28	const basePremiumForGroup = (type: string, count: number): number => {
29	  const spec = ITEM_TYPES[type];
30	  if (spec.isComponent && count === 3) return THREE_ALIKE_BLOCK_PREMIUM;
31	  return count * spec.basePremium;
32	};
33	
34	const basePremiumFor = (items: Item[]): number =>
35	  [...countByType(items)]
36	    .reduce((sum, [type, count]) => sum + basePremiumForGroup(type, count), 0);
37	
38	const applyFirstInsuranceSurcharge = (premium: number): number =>
39	  premium + (premium * FIRST_INSURANCE_SURCHARGE_PERCENT) / 100;
40	
41	const applyLoyaltyDiscount = (premium: number, yearsWithMHPCO: number): number =>
42	  yearsWithMHPCO >= 2 ? premium - (premium * 20) / 100 : premium;
43	
44	const quotePremium = (items: Item[], yearsWithMHPCO: number): number => {
45	  const afterLoyalty = applyLoyaltyDiscount(basePremiumFor(items), yearsWithMHPCO);
46	  return Math.ceil(applyFirstInsuranceSurcharge(afterLoyalty)) + PROCESSING_FEE;
47	};
48	
49	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
50	  const years = scenario.customer.yearsWithMHPCO;
51	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items, years) }));
52	  return { results };
53	};
54

